INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 112028, "vo_wac_220215_005", "", 0, "", 21, 112, 0, "", "vo_wac_220215");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 112029, "ランドソルを囲む壁に絵を？\nふぅん、楽しそうね。\nここに描けばいいのかしら？", 0, 1, 0.5, 11, 112, 10, 0, 106431);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 112030, "", "", "", "", 91, 112, "", "", 112029);
