INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 112039, "え？　ランドソルの壁を……\nぐるっと一周？", 0, 1, 0.5, 11, 112, 10, 0, 106431);
