INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 5012023, "平気だよ～！\nユイちゃんもレイさんもすっごく\n上手だもん！　ま、まああたしも\nちょっと照れくさいけど。えへへ。", 0, 1, 0.5, 11, 5012, 10, 0, 100111);
