INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 8512027, "そんなことないよ、アヤネちゃん……！\nすっごく元気が出てくるような絵で\n私は、大好きだよ……♪", 0, 1, 0.5, 11, 8512, 10, 0, 102111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 8512028, "", "", "", "", 91, 8512, "", "", 0);
