INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 8512032, "そうね。\nのびのびとした描き方で、\n見ていて気持ちいいわ。\nとってもアヤネらしいわね。", 0, 1, 0.5, 11, 8512, 10, 0, 102811);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 8512033, "", "", "", "", 91, 8512, "", "", 0);
