INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 8512037, "みんなよく描けてます……！\n私のドジで台無しにしちゃいそうで\n不安になってきました……っ！", 0, 1, 0.5, 11, 8512, 10, 0, 102511);
