INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 8612027, "そうね。慣れないせいもあって\n緊張しちゃうけど、\nコッコロさんやみんなが一緒だと\n落ち着いて、楽しくやれる気がするわ。", 0, 1, 0.5, 11, 8612, 10, 0, 106411);
