INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 8612032, "一人よりみんなの方が、\n落ち着いて楽しく過ごせる……か。\nあたしたちが囲む食卓と\n一緒ってことかしらね。", 0, 1, 0.5, 11, 8612, 10, 0, 106011);
