INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112024, "vo_wac_220705_000", "", 0, "", 21, 14112, 0, "", "vo_wac_220705");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112025, "やった！　これにて完成でござるよ～！\nう～ん、色使いといい、タッチといい、\n今度も素晴らしい出来栄えですな～！", 0, 1, 0.5, 11, 14112, 10, 0, 101311);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112026, "", "", "", "", 91, 14112, "", "", 0);
