INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112028, "wac_talk_smile_in_L", 0.2, "wac_talk_smile_loop_L", "", 3, 14112, 0, "", 105611);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112029, "vo_wac_220705_001", "", 0, "", 21, 14112, 0, "", "vo_wac_220705");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112030, "上出来、上出来。\nさて、絵も完成したことだし、\nみんなでパパっと片づけをして\n食事にでも行くとするかい。", 0, 1, 0.5, 11, 14112, 10, 0, 105611);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112031, "", "", "", "", 91, 14112, "", "", 0);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112032, "wac_idle_smile_L", 0.2, "", "", 3, 14112, 1, "", 105611);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112033, "wac_talk_doya_in", 0.2, "wac_talk_doya_loop", "", 3, 14112, 0, "", 105111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112034, "vo_wac_220705_002", "", 0, "", 21, 14112, 0, "", "vo_wac_220705");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112035, "あら？　でも……\n片づけはもう済んでるみたいよ？\nうふふ、いったいどこの「いい子」が\nやってくれたのかしらね～？", 0, 1, 0.5, 11, 14112, 10, 0, 105111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112036, "", "", "", "", 91, 14112, "", "", 0);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112037, "wac_idle_doya", 0.2, "", "", 3, 14112, 1, "", 105111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112038, "wac_talk_smile_in_L", 0.2, "wac_talk_smile_loop_L", "", 3, 14112, 0, "", 102711);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112039, "vo_wac_220705_003", "", 0, "", 21, 14112, 0, "", "vo_wac_220705");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112040, "クスクス……私は見ていましたよ。\nアンナさん、あなたがいそいそと\n後ろで道具を片づけているのを……", 0, 1, 0.5, 11, 14112, 10, 0, 102711);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112041, "", "", "", "", 91, 14112, "", "", 0);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112042, "wac_idle_smile_L", 0.2, "", "", 3, 14112, 1, "", 102711);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112043, "wac_talk_doya_in_L", 0.2, "wac_talk_doya_loop_L", "", 3, 14112, 0, "", 105611);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112044, "vo_wac_220705_004", "", 0, "", 21, 14112, 0, "", "vo_wac_220705");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112045, "はは、そりゃ助かった。\nお前さん、物言いは突飛だが、\nそういうところにはよく気が回るねえ。\nいい子じゃないか。", 0, 1, 0.5, 11, 14112, 10, 0, 105611);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112046, "", "", "", "", 91, 14112, "", "", 0);
