INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112048, "wac_talk_anger", 0.2, "", "", 3, 14112, 1, "", 100911);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14112049, "vo_wac_220705_005", "", 0, "", 21, 14112, 0, "", "vo_wac_220705");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14112050, "なっ、いい子とか言うなぁ！\nて、手がすいたからやっただけで、\nそこはせめて全知全能と……\nうぅ、生暖かい目で見るなぁっ！", 0, 1, 0.5, 11, 14112, 10, 0, 100911);
