INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14312022, "ふふ、絵を描くのって楽しいさ～！\n描いても描いても飽きないし……\n歌って踊ればもっと楽しくなるさ～！", 0, 1, 0.5, 11, 14312, 10, 0, 101711);
