INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14312027, "バ、バカ！　絵筆持ったまま\n踊るなって！　尻尾に\n絵の具がつくと落とすの大変なんだよ！", 0, 1, 0.5, 11, 14312, 10, 0, 104311);
