INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14712026, "シグルドー！　見てくれ見てくれ！\n今回の絵は、歴史に残る最高傑作……！\n貴様には、その目撃者になる\n栄誉を授けよう！", 0, 1, 0.5, 11, 14712, 10, 0, 100911);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14712027, "", "", "", "", 91, 14712, "", "", 0);
