INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14712031, "さすがだね、アンナたそ！\nけど私も負けないよ～！\n芸術の神が舞い降りたかのような\nこの完成度、ぜひご照覧あれ～！", 0, 1, 0.5, 11, 14712, 10, 0, 101311);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 14712032, "", "", "", "", 91, 14712, "", "", 0);
