INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 14712046, "はは、アタシの筆さばきだって\nなかなか様になってたろう？\n……それで？　お前さんは\n誰の絵が一番だと思うんだい？", 0, 1, 0.5, 11, 14712, 10, 0, 105611);
