INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16112018, "ふぅ……たまにはこうして\n童心に帰って一心に絵を描く\nっていうのもいいものだねぇ……", 0, 1, 0.5, 11, 16112, 10, 0, 106811);
