INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16112022, "vo_wac_220725_001", "", 0, "", 21, 16112, 0, "", "vo_wac_220725");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16112023, "うわあ！　マスターってば\n絵も上手なんですね！　でも\n言い方がお婆ちゃんみたいですよ？\nなるほど、これが亀の甲羅で逃避行！", 0, 1, 0.5, 11, 16112, 10, 0, 101111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16112024, "", "", "", "", 91, 16112, "", "", 0);
