INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16112028, "リノちゃん、こーら☆\nそんな言い方失礼だよ？\nマスターはいつも忙しくて\n大変なんだから。", 0, 1, 0.5, 11, 16112, 10, 0, 104911);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16112029, "", "", "", "", 91, 16112, "", "", 0);
