INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16112033, "ごめんごめん少し感慨深くてさ。\n確かに老け込むには早いね。\nなにせまだまだこの世界には\n解き明かすべき謎がいっぱいだ。", 0, 1, 0.5, 11, 16112, 10, 0, 106811);
