INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16412025, "よし、今度も素晴らしい完成度だ！\n役割分担をしたら、飛躍的に\n描くのが早くなったな！", 0, 1, 0.5, 11, 16412, 10, 0, 105311);
