INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16412030, "シュバッ！　シュバババッ！\n色塗りはワタシにお任せデース！\nこの絵筆二刀流で、瞬く間に\nカラフルにしてみせマース！", 0, 1, 0.5, 11, 16412, 10, 0, 103011);
