INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16412040, "それをクウカがなぞって……\nはぁっ、もし皆さんの作業を\n台無しにしちゃったらって思うと……\nす、すごく……興奮しますぅ……！", 0, 1, 0.5, 11, 16412, 10, 0, 104511);
