INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16412045, "あっ、道具のお片づけは\n私がしておきました……\nこういう地味な作業でも、\nお役に立ててるといいんですけど……", 0, 1, 0.5, 11, 16412, 10, 0, 105511);
