INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16612029, "wac_talk_sad_in", 0.2, "wac_talk_sad_loop", "", 3, 16612, 0, "", 102711);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612030, "vo_wac_220730_001", "", 0, "", 21, 16612, 0, "", "vo_wac_220730");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16612031, "ちょ、ちょっとアンナさん……\nあなた全身、絵の具だらけで\n動くたびに飛び散ってますわ。\n少し大人しくしてもらえますか？", 0, 1, 0.5, 11, 16612, 10, 0, 102711);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612032, "", "", "", "", 91, 16612, "", "", 0);
