INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16612034, "wac_talk_smile_in", 0.2, "wac_talk_smile_loop", "", 3, 16612, 0, "", 101311);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612035, "vo_wac_220730_002", "", 0, "", 21, 16612, 0, "", "vo_wac_220730");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16612036, "あははっ！　そういうエリコ様も\nおててが絵の具だらけでござるよ～！\nむふふ、いわゆるギャップ萌え\nというやつですな？", 0, 1, 0.5, 11, 16612, 10, 0, 101311);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612037, "", "", "", "", 91, 16612, "", "", 0);
