INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612039, "wac_talk_surprise_loop_shy", 0.2, "", "", 3, 16612, 1, "", 105111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612040, "vo_wac_220730_003", "", 0, "", 21, 16612, 0, "", "vo_wac_220730");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16612041, "まったくもう……\nみんなして絵の具まみれじゃない。\nって、あら？　この赤いのは……", 0, 1, 0.5, 11, 16612, 10, 0, 105111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612042, "", "", "", "", 91, 16612, "", "", 0);
