INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 16612045, "vo_wac_220730_004", "", 0, "", 21, 16612, 0, "", "vo_wac_220730");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 16612046, "ふふ、そういうアンタも、\nほっぺに絵の具がついてるじゃないか。\nほら、きれいにしてやるから\nそこに並びな、アンタたち。", 0, 1, 0.5, 11, 16612, 10, 0, 105611);
