INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17812022, "これで担当分はおしまいかな？\n剣術も芸術も、雑念を振り払い、\n一意専心に取り組むのが\nうまくいくコツな気がするよ。", 0, 1, 0.5, 11, 17812, 10, 0, 103711);
