INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17812027, "トモちゃんは真面目だね。\n私は絵の具が鎧にはねたら\nどうしようって、そればかり\n考えていたよ。", 0, 1, 0.5, 11, 17812, 10, 0, 104711);
