INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 17812032, "自分は、トラタイガーの\nことを考えながら描いてたッス！\n正義のヒーローへの憧れと情熱を、\nランドソルの壁に叩きつけたッス！", 0, 1, 0.5, 11, 17812, 10, 0, 100511);
