INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18712009, "見るがいい、シグルドよ！\n熾炎戦鬼煉獄血盟暗黒団にふさわしい、\n運命の交わりを感じさせるような\n大作に仕上がったぞ！！", 0, 1, 0.5, 11, 18712, 10, 0, 100911);
