INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812029, "wac_talk_doya_in_surprise_L", 0.2, "wac_talk_doya_loop_surprise_L", "", 3, 18812, 0, "", 100911);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812030, "vo_wac_220821_001", "", 0, "", 21, 18812, 0, "", "vo_wac_220821");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812031, "むっ、ちょっと待て。\nこの絵のテーマは、繰り返される\n運命の闘争が織りなす限りなき\nウロボロスの循環ではないのか！？", 0, 1, 0.5, 11, 18812, 10, 0, 100911);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812032, "", "", "", "", 91, 18812, "", "", 0);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812033, "wac_idle_doya_surprise_L", 0.2, "", "", 3, 18812, 1, "", 100911);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812034, "wac_talk_wish_in_L", 0.2, "wac_talk_wish_loop_L", "", 3, 18812, 0, "", 102711);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812035, "vo_wac_220821_002", "", 0, "", 21, 18812, 0, "", "vo_wac_220821");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812036, "クスクス……違います。\nこれはあのおかたへの愛……\n枯れることのない、永遠の愛が\nテーマですわ……", 0, 1, 0.5, 11, 18812, 10, 0, 102711);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812037, "", "", "", "", 91, 18812, "", "", 0);
