INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812040, "vo_wac_220821_003", "", 0, "", 21, 18812, 0, "", "vo_wac_220821");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812041, "これってテーマなんてあったの？\nあくまでギルドの仕事であって、\n指示書に忠実に描けばいいと\n思ってたんだけれど。", 0, 1, 0.5, 11, 18812, 10, 0, 105111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812042, "", "", "", "", 91, 18812, "", "", 0);
