INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812044, "wac_talk_arm_crossed_in", 0.2, "wac_talk_arm_crossed_loop", "", 3, 18812, 0, "", 105611);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812045, "vo_wac_220821_004", "", 0, "", 21, 18812, 0, "", "vo_wac_220821");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 18812046, "いやいや、それであってるよ。\nアイツら、やる気満々なのはいいけど、\n余計なもん描き足してないだろうね？\nあとで見ておくか……", 0, 1, 0.5, 11, 18812, 10, 0, 105611);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 18812047, "", "", "", "", 91, 18812, "", "", 0);
