INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 19812044, "そ、そうですね……\nドＳさんも多種多様な攻めを\n繰り出してきますけど、全部\nクウカにとっては快感ですし。", 0, 1, 0.5, 11, 19812, 10, 0, 104511);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 19812045, "", "", "", "", 91, 19812, "", "", 0);
