INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 19812049, "それは流石に違う気がします……\nでも、みんなで描いた絵が、\n浮世絵みたいにきれいに\nできたのはそのとおりですね♪", 0, 1, 0.5, 11, 19812, 10, 0, 105511);
