INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 20012027, "はい、大変お上手でございます。\nぺコリーヌさまとシェフィさまの\n絵も、負けないくらいお上手ですよ？\nいっぱい、褒めて差し上げますね。", 0, 1, 0.5, 11, 20012, 10, 0, 105911);
