INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 20012032, "あ、ありがとう、コッコロさん。\n……純粋に褒めてくれてるのは\n分かるんだけど、どうにも\nこそばゆい感じがするわね。", 0, 1, 0.5, 11, 20012, 10, 0, 106411);
