INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 20312023, "い、いいところ……！？\nハツネさんのいいところは、\nえーっと、あ、明るくて！\n優しいところだと思います！", 0, 1, 0.5, 11, 20312, 10, 0, 104011);
