INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 21112009, "しかし何だな、この作業……\nぼく個人の芸術性は不要と言うなら、\nぼくが筆を持つ必然はあるのだろうか。", 0, 1, 0.5, 11, 21112, 10, 0, 111011);
