INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 21112013, "いや、だが、これは国家事業だ。\n端的に換言すれば、金のためだ。\n商業と創作の狭間で葛藤するぼく──\nおお、まさに芸術家ならではの苦悩！", 0, 1, 0.5, 11, 21112, 10, 0, 111011);
