INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 21312023, "あァ、国家そういうトコあんだよ。\nうちも前に世界救う的なバイトしたけど\nあいつあんときの日給まだくんないわ。", 0, 1, 0.5, 11, 21312, 10, 0, 110811);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 21312024, "", "", "", "", 91, 21312, "", "", 0);
