INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 21312028, "まあまあ、落ちつけ後輩たち。\n慌てる理系は貰いが少ないと言うぞ。\n国家予算ともなれば、相応に煩雑な\n手続きがあるのだろう。座して待て。", 0, 1, 0.5, 11, 21312, 10, 0, 111011);
