INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23212022, "ふぅ、これでできあがりね。\nみんなもすごく上手に描けてるし、\nよく頑張ったわね♪", 0, 1, 0.5, 11, 23212, 10, 0, 102811);
