INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812025, "vo_wac_221010_000", "", 0, "", 21, 23812, 0, "", "vo_wac_221010");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812026, "はぁ、思わずため息が出るよ。\nかわいいボクが、美しい絵を描く。\nただそれだけで、言葉にできないほど\n尊い場面になってしまうよね？", 0, 1, 0.5, 11, 23812, 10, 0, 100811);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812027, "", "", "", "", 91, 23812, "", "", 0);
