INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812029, "wac_talk_wish_in", 0.2, "wac_talk_wish_loop", "", 3, 23812, 0, "", 104511);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812030, "vo_wac_221010_001", "", 0, "", 21, 23812, 0, "", "vo_wac_221010");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812031, "そ、そうですね……\nそんなきれいな風景の中で、\nただ一人辱めを受けている\n自分とかを想像すると……じゅるり♪", 0, 1, 0.5, 11, 23812, 10, 0, 104511);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812032, "", "", "", "", 91, 23812, "", "", 0);
