INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812034, "wac_talk_doya_in_surprise_L", 0.2, "wac_talk_doya_loop_surprise_L", "", 3, 23812, 0, "", 103011);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812035, "vo_wac_221010_002", "", 0, "", 21, 23812, 0, "", "vo_wac_221010");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812036, "オー、まさに陰と陽！\nこれがゲージュツの分野で\nいうところの、コントラストと\nいうヤツなのでショウか？", 0, 1, 0.5, 11, 23812, 10, 0, 103011);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812037, "", "", "", "", 91, 23812, "", "", 0);
