INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812040, "vo_wac_221010_003", "", 0, "", 21, 23812, 0, "", "vo_wac_221010");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812041, "絶対に違うと思います……\n二人とも、自分の好きなものに\n忠実なだけというか……", 0, 1, 0.5, 11, 23812, 10, 0, 105511);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 23812042, "", "", "", "", 91, 23812, "", "", 0);
