INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 23812046, "ほら、いつまでも壁の前で\nダラダラしてないで帰るぞ！\n私たちに必要なのは、尊さだの\n芸術だのではなく、訓練なんだからな！", 0, 1, 0.5, 11, 23812, 10, 0, 105311);
