INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 25212023, "そういうのは今はいいですから！\nでもお姉ちゃん美人で頭良くて強いのに\n絵までうまいんですねえ……\nまさに文句上等？　ってやつですよ。", 0, 1, 0.5, 11, 25212, 10, 0, 101111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 25212024, "", "", "", "", 91, 25212, "", "", 0);
