INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 25712013, "けれど、悩ましい才能だよね。\nボクのかわいさと、描いた絵の美しさが\n競い合うようなことになったら……\nまぁ、ボクの方がかわいいよね♪", 0, 1, 0.5, 11, 25712, 10, 0, 100811);
