INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26212022, "ふぅ……これで完成、です。\n前よりも上手に描けたでしょうか？\nやっぱり絵を描くのって楽しいですね。", 0, 1, 0.5, 11, 26212, 10, 0, 103811);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 26212023, "", "", "", "", 91, 26212, "", "", 0);
