INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26212037, "あ、だったら、リマの背中を借りたら？\n今日は天気もいいし、いい感じに\nふわふわで最高だったよ～", 0, 1, 0.5, 11, 26212, 10, 0, 102611);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 26212038, "", "", "", "", 91, 26212, "", "", 0);
