INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26212042, "もう、リンちゃんったら、\nすぐに抱きついてくるんだから。\nでも、シオリちゃんが疲れてるなら、\n帰りはおんぶして運んであげるわよ♪", 0, 1, 0.5, 11, 26212, 10, 0, 105211);
