INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26222022, "よし、描けた。\nみんなで話し合ったりして、\nちょっと時間はかかったけど、\n悪くない出来じゃないかな？", 0, 1, 0.5, 11, 26222, 10, 0, 101411);
