INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26222027, "せやねぇ♪\nみんなでわいわいしながら、\nまったりと描くんも楽しかったわぁ♪\n絵にもそれが表れてます♪", 0, 1, 0.5, 11, 26222, 10, 0, 101011);
