INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26232023, "そんなことない！　バッチリだよ！\nやっぱりグレアは天才かも！\nアートの申し子で間違いない！\nルゥもそう思うでしょ！", 0, 1, 0.5, 11, 26232, 10, 0, 109211);
