INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 26232028, "ルゥの中にいるルゥも言ってます！\nグレアせんぱいは天才で、申し子です！\nルゥがラクガキの女王なら\nせんぱいはラクガキのゴッドです！", 0, 1, 0.5, 11, 26232, 10, 0, 109311);
