INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27012022, "こんなものかしら？\nムラなし、はみだしもなし。\n我ながら、指示書どおりの\n素晴らしい塗装ができたと思うわ♪", 0, 1, 0.5, 11, 27012, 10, 0, 104811);
