INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27012027, "まぁ、ミフユさんったら。\n私たちが手掛けているのはアート\nなんですから、もっと自由に、\n己の感性に従って描くべきですわ！", 0, 1, 0.5, 11, 27012, 10, 0, 103211);
