INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27012032, "そうそう～♪\n私もね、内なる芸術性を\n発揮するために、麦しゅわの\n力を借りてみたのよ～♪", 0, 1, 0.5, 11, 27012, 10, 0, 103411);
