INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27312009, "やはりこの姿だと、作業しやすいのう！\nふふっ、これもお主のおかげじゃな。\nどれ、少しなら褒美をやっても良いぞ？\nなに……絵を見れるだけで十分じゃと？", 0, 1, 0.5, 11, 27312, 10, 0, 104411);
