INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812030, "vo_wac_221119_001", "", 0, "", 21, 27812, 0, "", "vo_wac_221119");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812031, "おぉー、クウカがひいた曲線、\nすごくきれいデス！\nまるでウキヨエマスターみたいデスね！\nワタシにもその技、教えてクダサイ！", 0, 1, 0.5, 11, 27812, 10, 0, 103011);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812032, "", "", "", "", 91, 27812, "", "", 0);
