INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812034, "wac_talk_sad_in_surprise", 0.2, "wac_talk_sad_loop_surprise", "", 3, 27812, 0, "", 105511);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812035, "vo_wac_221119_002", "", 0, "", 21, 27812, 0, "", "vo_wac_221119");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812036, "ニ、ニノンさんも上手でしたけど、\nクウカさんもすごい……！\nでも、クウカさんが興奮してるのは、\n違う理由のような……", 0, 1, 0.5, 11, 27812, 10, 0, 105511);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812037, "", "", "", "", 91, 27812, "", "", 0);
