INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812040, "vo_wac_221119_003", "", 0, "", 21, 27812, 0, "", "vo_wac_221119");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812041, "うむ……もはや、何も言うまい。\nしかし共同作戦というのは悪くないな。\nこれはチームプレイの\n良い訓練になるぞ！", 0, 1, 0.5, 11, 27812, 10, 0, 105311);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812042, "", "", "", "", 91, 27812, "", "", 0);
