INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812046, "ふふっ、ボクが一番\n輝いちゃって申し訳ないけどね♪\n流れる汗も太陽に照らされて、\nボクを彩ってるみたいじゃないか♪", 0, 1, 0.5, 11, 27812, 10, 0, 100811);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 27812047, "", "", "", "", 91, 27812, "", "", 0);
