INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 27812051, "絵を描くだけで、こ、こんなに\n興奮できるなんて思いませんでした……\nきっとこの後もドＳさんから絵について\nあることないこと聞かれて……ぐふふ♪", 0, 1, 0.5, 11, 27812, 10, 0, 104511);
