INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 28112036, "私ももう少し描きたい、という\n気持ちはあるのですが……\nミヤコさんがもう限界みたいです。", 0, 1, 0.5, 11, 28112, 10, 0, 103111);
