INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 28112047, "さっきまで大人しく手伝っていたかと\n思えば……\nって、やめい！\nわらわはプリンなど持っておらんわ！", 0, 1, 0.5, 11, 28112, 10, 0, 104411);
