INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 28412031, "vo_wac_221125_002", "", 0, "", 21, 28412, 0, "", "vo_wac_221125");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 28412032, "このクリスティーナが手伝う以上、\n粗い仕事など許さん！\nまったく、オマエたちはもう少し、\n芸術を嗜むべきだぞ♪", 0, 1, 0.5, 11, 28412, 10, 0, 107111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 28412033, "", "", "", "", 91, 28412, "", "", 0);
