INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 28412042, "ジュンさん、それにみんなも、\n手伝ってくれてありがとうッス！\nおかげで、ワイルドなかっこいい絵に\n仕上がったッスよ♪", 0, 1, 0.5, 11, 28412, 10, 0, 100511);
