INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 31112031, "うん！\n……でも、このあたりって\n誰が色塗り担当だったっけ？\n気づいたら塗り終わってたよね？", 0, 1, 0.5, 11, 31112, 10, 0, 100611);
