INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 31112036, "知らない女の子が塗ってたの～\nミヤコが声をかけようとしたら、\nすーっと消えちゃったの。", 0, 1, 0.5, 11, 31112, 10, 0, 100711);
