INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 32112027, "【牧場（エリザベスパーク）】には、\nそんな高度な魔法を扱える人が\nいないので……お姉ちゃんなら\nできるかもしれないですけど。", 0, 1, 0.5, 11, 32112, 10, 0, 103811);
