INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 32112032, "でも、魔法でお絵描きって\nちょっと憧れるわね～♪\n頭で思い描いたとおりの\n絵ができあがるのかしら？", 0, 1, 0.5, 11, 32112, 10, 0, 105211);
