INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 33612012, "もう何度父がナンパした他のギルドの\n方々に頭を下げたか分かりません……\n次にやったらペンキ缶に沈めると\n伝えてからは、大人しくなりましたが。", 0, 1, 0.5, 11, 33612, 10, 0, 103111);
