INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 33812009, "……この仕事って、気を付けないと\n服が塗料で汚れちゃうのが困るわね。\n昨日はアカリが思いっきり汚してきて、\nお説教する羽目になったし。", 0, 1, 0.5, 11, 33812, 10, 0, 102211);
