INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 34312031, "……困りましたね。\n今日はもうミヤコさんに渡せるプリンが\nありませんが、どうしましょう？", 0, 1, 0.5, 11, 34312, 10, 0, 103111);
