INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 35312018, "これで完成……じゃない！\n指示書を見てから描いたのに、\nあちこち間違えてる……！\n正しい形に直さなきゃ！", 0, 1, 0.5, 11, 35312, 10, 0, 103611);
