INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 35812022, "むっ……おい、マツリちゃん。\nしっぽの先がペンキで汚れているぞ。\nどれ、ワタシが丁寧に拭ってやろう♪", 0, 1, 0.5, 11, 35812, 10, 0, 107111);
