INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 35812037, "嫌いだったら、あんな楽しそうに\n構いに行ったりしないからね。\nもう少し眺めていたいけれど……\nそろそろ、助け舟を出してあげようか。", 0, 1, 0.5, 11, 35812, 10, 0, 104711);
