INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 36912022, "ソルの塔から見てはいたけど、\n実際絵を描くとなると大変ね～\n……でも、悪くないわ。\nこうして、一緒に何か作るのって。", 0, 1, 0.5, 11, 36912, 10, 0, 123011);
