INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 36912032, "もちろん、この絵だけじゃないよ？\nこれからは一緒に、いろいろ\n楽しいことに挑戦していこ～♪", 0, 1, 0.5, 11, 36912, 10, 0, 100111);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 36912033, "", "", "", "", 91, 36912, "", "", 0);
