INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 36912037, "そうだね♪\n幸せ過ぎて、絶対に忘れたくない……\nもし忘れても、必ず思い出したい……\nそんな思い出を、作っていきたいな。", 0, 1, 0.5, 11, 36912, 10, 0, 100211);
