INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 37912021, "おい諸君、大変だ。\n国家予算こと我々の労働報酬について\nギルド管理協会に問い合わせたところ、\nそんなもん出ねえ的な回答があった。", 0, 1, 0.5, 11, 37912, 10, 0, 111011);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 37912022, "", "", "", "", 91, 37912, "", "", 0);
