INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 37912024, "wac_talk_smile_in_L", 0.2, "wac_talk_smile_loop_L", "", 3, 37912, 0, "", 110911);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 37912025, "vo_wac_230228_001", "", 0, "", 21, 37912, 0, "", "vo_wac_230228");
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 37912026, "またまた～！　そんなのアレですよ、\nそう言われてうちらがワーワー騒いでる\nところに、後ろからカリンねえさんが\nプラカード持って出てくるやつですよ。", 0, 1, 0.5, 11, 37912, 10, 0, 110911);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 37912027, "", "", "", "", 91, 37912, "", "", 0);
