INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 37912031, "「ドッキリ大成功です！」つってね。\nプラカードと国家予算持ってね。\nあるある、絶対ソレだわ。", 0, 1, 0.5, 11, 37912, 10, 0, 110811);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 37912032, "", "", "", "", 91, 37912, "", "", 0);
