INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 37912034, "あーウケる。\nしたらカリンさん出てくるまで、\nしばらくこのまま待っとこ。ね。", 0, 1, 0.5, 11, 37912, 10, 0, 110811);
