INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38012022, "今回も上手にできたにゃ～♪\nあたしたちも気づけばすっかり\n絵描きの風格になったにゃ。\nこれで新しい商売でも始めるにゃ？", 0, 1, 0.5, 11, 38012, 10, 0, 104611);
