INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38012027, "商売って……描いた絵を売るとか？\nうーん、別に芸術家として\n有名になったわけでもないし、\nちょっと難しいような……", 0, 1, 0.5, 11, 38012, 10, 0, 104811);
