INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38012032, "麦しゅわ！　麦しゅわの絵を描くの！\nそれをね～、酒場とかに売って～……\nそのお金で、麦しゅわを買うの～♪\n……ひっく。", 0, 1, 0.5, 11, 38012, 10, 0, 103411);
