INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38612026, "ふぅ、これでいいかしら？\n普段もカルテにスケッチを描く機会は\nあるけれど、絵筆を使ってしっかりと\n描くのはなかなか大変ね……", 0, 1, 0.5, 11, 38612, 10, 0, 105111);
