INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38612031, "でも、楽しいお仕事ですぞ～♪\nできればもうすこ～し、\n魔法少女チックな要素を\n付け足せたらとは思ったけど……", 0, 1, 0.5, 11, 38612, 10, 0, 101311);
