INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38612036, "いや、どうせ付け足すのならば\nこの疾風の冥姫がいかにして\n呪われし運命を克服していったか、\nその神話が分かるような壁画を……", 0, 1, 0.5, 11, 38612, 10, 0, 100911);
