INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 38612041, "いいえ……運命の物語を描くなら、\n私とあなた様との出会いから今までを\n描いた方が素敵ですわよね……\nクスクス……♪", 0, 1, 0.5, 11, 38612, 10, 0, 102711);
