INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 39512037, "大人限定ではあるけれど、手っ取り早く\n楽しい気分になれる方法なのよ……\nでも元気の前借りみたいなものだから、\nやっぱりほどほどに飲むのが一番だわ。", 0, 1, 0.5, 11, 39512, 10, 0, 104811);
