INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 40922004, "……というわけで！\nカリンさん、お待たせしました。\nランドソルの景観向上事業、\n全力全開でやり遂げましたよ☆", 0, 1, 0.5, 11, 40922, 10, 0, 105811);
