INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 40922009, "みなさん、本当にお疲れさまでした！\nこれだけ大きな壁に絵を描くのは\n大変だったと思いますが、\nとても鮮やかな景観になりましたよ♪", 0, 1, 0.5, 11, 40922, 10, 0, 118511);
