INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 40922014, "そうでございますね。\n【美食殿】だけでなく、多くのギルドの\nみなさまが力を合わせた結果、\n美しい壁になったのだと思います。", 0, 1, 0.5, 11, 40922, 10, 0, 105911);
