INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (1, 40922030, "そんなこと言って、キャルちゃんも\nノリノリで描いてたじゃないですか♪\n絵の才能があるかもーって\nみんなに自慢もしてましたし。", 0, 1, 0.5, 11, 40922, 10, 0, 105811);
